module asyn_fifo
#(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)
(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output [WIDTH-1:0] rdata_out,
    output wfull,
    output rempty
);

    reg [$clog2(DEPTH)-1:0] waddr_bin;
    reg [$clog2(DEPTH)-1:0] raddr_bin;
    reg [$clog2(DEPTH):0] wptr;
    reg [$clog2(DEPTH):0] rptr;
    reg [$clog2(DEPTH):0] wptr_buff;
    reg [$clog2(DEPTH):0] rptr_buff;
    wire wen;
    wire ren;
    wire [WIDTH-1:0] wdata_in;


    dual_port_RAM #(.DEPTH(DEPTH), .WIDTH(WIDTH)) ram_inst (
        .wclk(wclk),
        .wenc(wen),
        .waddr(waddr_bin),
        .wdata(wdata_in),
        .rclk(rclk),
        .renc(ren),
        .raddr(raddr_bin),
        .rdata(rdata_out)
    );

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            waddr_bin <= 0;
        end else if (winc) begin
            waddr_bin <= waddr_bin + 1;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            raddr_bin <= 0;
        end else if (rinc) begin
            raddr_bin <= raddr_bin + 1;
        end
    end

    assign wptr = {waddr_bin[$clog2(DEPTH)], waddr_bin[$clog2(DEPTH)-1:0]};
    assign rptr = {raddr_bin[$clog2(DEPTH)], raddr_bin[$clog2(DEPTH)-1:0]};

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            wptr_buff <= 0;
        end else begin
            wptr_buff <= wptr;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            rptr_buff <= 0;
        end else begin
            rptr_buff <= rptr;
        end
    end

    assign wfull = (wptr == {~rptr_buff[$clog2(DEPTH)], rptr_buff[$clog2(DEPTH)-1:0]});
    assign rempty = (rptr == wptr);

    assign wen = winc & !wfull;
    assign ren = rinc & !rempty;

    assign wdata_in = wdata;
    assign rdata_out = rdata_out;
endmodule
